        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), g = f.getItem("d08")._controlBehavior, v = f._language == 'v';
var e1 = (v ? 'Có tồn tại mã nhân viên trùng nhau trong phần thông tin chi tiết, không thể lưu được.' : 'Invalid employee id, it already exists.');
var e2 = (v ? 'Trường <span class="Highlight">Công ty hỗ trợ</span> không được < 0 hoặc > 100.' : 'The field <span class="Highlight">Supported by Company</span> not < 0 or > 100.');
var l2 = g._getColumnOrder('ma_nv'), t1 = f.getItemValue('tl_ho_tro');

if (t1 < 0 || t1 > 100) {
  $func.hideWait(id);
  $message.show(e2, String.format('$find(\'{0}\').getItem(\'tl_ho_tro\').focus()', id));
  f._checked = false;
}
if (f._checked) {
  var a = query$Select(g, 'count$1 $groupBy ma_nv');
  for (var i = 0; i < a.length; i++) {
    if (a[i][1] > 1) {
      f._checked = false;
      $func.hideWait(id);
      for (var j = 1; j <= g._rowCount; j++) {
        g._errorMultiEmployee = g._getItem(j, l2);
        if(a[i][0] == g._getItemValue(j, l2)){
          $message.show(e1, String.format('$find(\'{0}\').focus(\'d08\');$find(\'{1}\')._errorMultiEmployee.focus()', id, g.get_id()));
          break;
        }
      }
      break;
    }
  }
}
