script.text:
      &ScriptQueryData;
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, null, null, null, 'status');}
/* </flatten> */
function active$Voucher$(f) {
  f.add_onResponseComplete(on$Voucher$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (!f._$handleStatus) {
    var o = f.getItem('status');
    f._$handleStatus = [];
    for (var i = 0; i < o.options.length; i++) Array.add(f._$handleStatus, o.options[i]);
  }
  set$Voucher$DefaultValue(f);
  objectBehavior$Dir$Code.create(f, 'ma_khoa', 'ma_khoa', 'hrdtkh');
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {set$Voucher$DefaultValue(f);&VoucherLogHandleStatus;}
function close$Voucher$(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Voucher$ResponseComplete);} catch (ex) {}
  if (f._upload$Extender) {
    try {f._upload$Extender.remove_commandEvent(listView$ExecuteCommand);} catch (ex) {}
    f._upload$Extender.dispose();
    f._upload$Extender = null;
  }
  &ListDispose;
  &PostDispose;
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d08', 'r08', 'giang_vien'&ListTabChange;&PostTabChange;, 'so_gio']);
  &PostTabFocus;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d08')._controlBehavior, y = f.getItem('r08')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      break;
    case 'Explore':
      var o = f.getItem('status');
      set$Voucher$AddStatus(o);
      &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Suggestion':
      objectBehavior$Dir$Code.suggestion(f, result[0].Value);
      break;
    case 'Scattering':
      set$Voucher$DefaultValue(f);
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$AddStatus(o) {
  var f = o.parentForm;
  if (o.options.length < 5) {
    for (var i = 4; i < 5; i++) o.options.add(f._$handleStatus[i]);
  }
}
function set$Voucher$DefaultValue(f) {
  if (f._action == 'New') { f.setItemValue('ngay_ct', new Date()); }
  if (f._action != 'View') {
    var o = f.getItem('status');
    if (o.options.length >= 4) {
      for (var i = 4; i > 3; i--) o.options.remove(i);
    }
  }
}
function onChange$Voucher$PlannedDate(o, v) {o.parentForm.getItem('ngay_hoc' + v).value = o.parentForm.getItem('ngay_du_kien' + v).value;}
function onChange$Voucher$TotalCost(o, v) {
  var f = o.parentForm;
  f.setItemValue('t_cp' + v, f.getItemValue('sl_hv' + v) * f.getItemValue('cp' + v));
}
function when$VoucherCopying(f) {if (f.grid._dvHandle != null) f.setItemValue('status', f.grid._dvHandle);}
/* </flatten> */
      &ScriptSuggestion;
      &ListScript;
      &PostScript;
